blocks.body:
{
    "level": "A2–B1",
    "intro": "W tym temacie nauczysz się <strong>zaimków nieokreślonych</strong> - słów oznaczających nieokreślone osoby, rzeczy i miejsca.",
    "rules": [
        {
            "label": "KTOŚ-",
            "color": "emerald",
            "text": "<strong>Ktoś-</strong> w oświadczeniach:",
            "example": "Ktoś dzwonił. Coś się wydarzyło."
        },
        {
            "label": "KAŻDY-",
            "color": "blue",
            "text": "<strong>Dowolny-</strong> w pytaniach i zastrzeżeniach:",
            "example": "Czy ktoś to widział? Nic nie widziałem."
        },
        {
            "label": "NIE-",
            "color": "rose",
            "text": "<strong>Nie-</strong> w przypadku sprzeciwu:",
            "example": "Nikt nie wie. Nic się nie stało."
        }
    ]
}

{
    "title": "1. Cztery grupy zaimków nieokreślonych",
    "intro": "Zaimki nieokreślone dzielą się na cztery główne grupy:",
    "items": [
        {
            "label": "KTOŚ-",
            "title": "Ktoś, coś",
            "subtitle": "ktoś/ktoś, coś, gdzieś — w oświadczenia"
        },
        {
            "label": "KAŻDY-",
            "title": "Każdy, cokolwiek",
            "subtitle": "każdy/ktokolwiek, cokolwiek, gdziekolwiek – w pytaniach i zastrzeżeniach"
        },
        {
            "label": "NIE-",
            "title": "Nikt, nic",
            "subtitle": "nikt/nikt, nic, nigdzie – do negacji"
        },
        {
            "label": "KAŻDY-",
            "title": "wszyscy, wszystko",
            "subtitle": "wszyscy/wszyscy, wszystko, wszędzie – wszyscy bez wyjątku"
        }
    ]
}

{
    "title": "2. Pełna tabela zaimków nieokreślonych",
    "intro": "Trzy kategorie: ludzie (-one/-body), rzeczy (-thing), miejsca (-where):",
    "rows": [
        {
            "en": "KTOŚ-",
            "ua": "ktoś, coś, gdzieś",
            "note": "ktoś/ktoś, coś, gdzieś"
        },
        {
            "en": "KAŻDY-",
            "ua": "ktoś/ktokolwiek, cokolwiek, gdziekolwiek",
            "note": "anyone/anybody, anything, anywhere"
        },
        {
            "en": "NIE-",
            "ua": "nikt/nikt, nic, nigdzie",
            "note": "nikt/nikt, nic, nigdzie"
        },
        {
            "en": "każdy-",
            "ua": "wszyscy/wszyscy, wszystko, wszędzie",
            "note": "everyone/everybody, everything, everywhere"
        }
    ],
    "warning": "📌 -jeden/-ciało (ludzie), -rzecz (rzeczy), -gdzie (miejsca)."
}

{
    "title": "3. COŚ- (ktoś, coś, gdzieś) drzwi.",
    "sections": [
        {
            "label": "У ствердженнях",
            "color": "emerald",
            "description": "Займенники з <strong>some-</strong> використовуються в <strong>стверджувальних реченнях</strong>.",
            "examples": [
                {
                    "en": "Someone is at the door.",
                    "ua": "Хтось біля дверей."
                },
                {
                    "en": "Widziałem kogoś w ogrodzie.",
                    "ua": "Widziałem kogoś w ogrodzie."
                },
                {
                    "en": "Coś jest nie tak.",
                    "ua": "Coś jest nie tak."
                },
                {
                    "en": "Zostawiłem klucze gdzieś.",
                    "ua": "Zostawiłem gdzieś klucze."
                }
            ]
        },
        {
            "label": "W pytaniach (sugestiach)",
            "color": "sky",
            "description": "Some- jest również używane w <strong>pytaniach-sugestiach</strong> lub gdy oczekujemy odpowiedzi twierdzącej.",
            "examples": [
                {
                    "en": "Chcesz coś do się napić?",
                    "ua": "Czy chcesz coś do picia?"
                },
                {
                    "en": "Czy ktoś może mi pomóc?",
                    "ua": "Хтось може мені допомогти?"
                },
                {
                    "en": "Did you go somewhere nice?",
                    "ua": "Ти ходив кудись гарно?"
                }
            ],
            "note": "📌 У питаннях-пропозиціях використовуємо some-, не any-!"
        },
        {
            "label": "Someone vs Somebody",
            "color": "purple",
            "description": "<strong>Ktoś</strong> i <strong>ktoś</strong> to synonimy. To samo z czymś.",
            "examples": [
                {
                    "en": "Ktoś zadzwonił = Ktoś zadzwonił",
                    "ua": "Ktoś zadzwonił"
                },
                {
                    "en": "Usłyszałem coś = Usłyszałem hałas",
                    "ua": "Ktoś/coś jest nieco bardziej formalne. Ktoś rozmawia."
                }
            ],
            "note": "Someone/something — трохи формальніше. Somebody — розмовне."
        }
    ]
}

{
    "title": "4. ANY- (każdy, cokolwiek, gdziekolwiek)",
    "sections": [
        {
            "label": "W pytaniach",
            "color": "blue",
            "description": "Zaimki z <strong>any-</strong> są używane w <strong>pytaniach</strong>.",
            "examples": [
                {
                    "en": "Czy ktoś dzwonił?",
                    "ua": "Ktoś dzwonił?"
                },
                {
                    "en": "Czy ktoś jest w domu?",
                    "ua": "Czy ktoś jest w domu?"
                },
                {
                    "en": "Widziałeś coś?",
                    "ua": "Widziałeś coś?"
                },
                {
                    "en": "Wybierasz się gdziekolwiek? negacje",
                    "ua": "Ти кудись йдеш?"
                }
            ]
        },
        {
            "label": "У запереченнях",
            "color": "sky",
            "description": "Any- jest również używane w <strong>negacjach</strong> (z not).",
            "examples": [
                {
                    "en": "Nie widziałem nikogo.",
                    "ua": "Nie widziałem nikogo."
                },
                {
                    "en": "Ona nie wie nikogo.",
                    "ua": "Ona nie wie, że ktoś wie."
                },
                {
                    "en": "Niczego nie kupiłem.",
                    "ua": "Niczego nie kupiłem."
                },
                {
                    "en": "Nigdzie nie poszliśmy.",
                    "ua": "Nie poszliśmy gdziekolwiek."
                }
            ],
            "note": "📌 Nie + jakikolwiek- = nie- (obie opcje poprawne)."
        },
        {
            "label": "Każdy, cokolwiek (w oświadczeniach)",
            "color": "purple",
            "description": "W oświadczeniach jakikolwiek- oznacza <strong>kogokolwiek, cokolwiek</strong> (bez ograniczeń).",
            "examples": [
                {
                    "en": "Każdy może to zrobić to.",
                    "ua": "Każdy może to zrobić."
                },
                {
                    "en": "Możesz wziąć, co chcesz.",
                    "ua": "Możesz wziąć, co chcesz."
                },
                {
                    "en": "Możemy udać się gdziekolwiek.",
                    "ua": "Możemy udać się gdziekolwiek."
                }
            ],
            "note": "Wyrażenia any-in = „dowolne”, „bez ograniczeń”."
        }
    ]
}

{
    "title": "5. NIE- (nikt, nic, nigdzie)",
    "sections": [
        {
            "label": "Dla negacji",
            "color": "rose",
            "description": "Zaimki z <strong>no-</strong> same tworzą <strong>przeczenie</strong>. Nie musisz!",
            "examples": [
                {
                    "en": "Nikt nie zna odpowiedzi.",
                    "ua": "Nikt nie zna odpowiedzi."
                },
                {
                    "en": "Nikt nie przyszedł na imprezę.",
                    "ua": "Nikt nie przyszedł na imprezę."
                },
                {
                    "en": "Nic nie jest niemożliwe.",
                    "ua": " niemożliwe."
                },
                {
                    "en": "Nie byłem nigdzie interesujący.",
                    "ua": "Nie byłem nigdzie interesujący."
                }
            ],
            "note": "📌 NIE- już odmowa! Nie dodawaj nie!"
        },
        {
            "label": "Nikt = Nikt",
            "color": "amber",
            "description": "Nie- i nie + jakikolwiek- to synonimy. Obie opcje są prawidłowe.",
            "examples": [
                {
                    "en": "Nikt nie dzwonił = nikt nie dzwonił",
                    "ua": "Nikt nie dzwonił"
                },
                {
                    "en": "Nie widziałem nikogo = nikogo nie widziałem",
                    "ua": "Nie widziałem nikogo nic"
                },
                {
                    "en": "She didn't say anything = She said nothing",
                    "ua": "Nie powiedziała cokolwiek"
                }
            ],
            "note": "Nie – trochę bardziej formalnie i kategorycznie."
        },
        {
            "label": "Błąd: podwójna negacja!",
            "color": "red",
            "description": "W języku angielskim NIE można używać podwójnej negacji!",
            "examples": [
                {
                    "en": "Nie widziałem nikogo. (✗)",
                    "ua": "BŁĄD - podwójna negacja!"
                },
                {
                    "en": "Nie widziałem nikogo. (✓)",
                    "ua": "Nikogo nie widziałem."
                },
                {
                    "en": "Nikogo nie widziałem. (✓)",
                    "ua": "Nie widziałem nikogo."
                }
            ],
            "note": "📌 Nie + nie- = BŁĄD! Wybierz jedną: nie + żaden- LUB nie-."
        }
    ]
}

{
    "title": "6. KAŻDY- (wszyscy, wszystko, wszędzie)",
    "sections": [
        {
            "label": "Wszyscy bez wyjątku",
            "color": "purple",
            "description": "Zaimki z <strong>every-</strong> oznaczają <strong>wszystkich bez wyjątku</strong>.",
            "examples": [
                {
                    "en": "Wszyscy tu są.",
                    "ua": "Wszyscy tutaj."
                },
                {
                    "en": "Każdy to wie. pojedynczy!",
                    "ua": "Усі це знають."
                },
                {
                    "en": "Everything is fine.",
                    "ua": "Усе гаразд."
                },
                {
                    "en": "I've looked everywhere.",
                    "ua": "Я шукав скрізь."
                }
            ]
        },
        {
            "label": "З дієсловом в однині!",
            "color": "amber",
            "description": "Wszyscy/wszyscy są <strong>pojedynczy</strong>! Czasownik występuje w liczbie pojedynczej.",
            "examples": [
                {
                    "en": "Wszyscy są gotowi. (✓)",
                    "ua": "Wszyscy są gotowi."
                },
                {
                    "en": "Wszyscy są gotowi. (✗)",
                    "ua": "BŁĄD - czasownik powinien brzmieć is!"
                },
                {
                    "en": "Każdy ma bilet.",
                    "ua": "Każdy ma bilet."
                }
            ],
            "note": "📌 Każdy/wszyscy = liczba pojedyncza (jest, ma, robi)."
        },
        {
            "label": "Wszyscy kontra wszyscy",
            "color": "sky",
            "description": "<strong>Wszyscy</strong> i <strong>wszyscy</strong> to synonimy.",
            "examples": [
                {
                    "en": "Wszyscy są mile widziani = wszyscy są mile widziani",
                    "ua": "Wszyscy są mile widziani"
                }
            ],
            "note": "Wszyscy jest trochę bardziej formalny. Wszyscy rozmawiają."
        }
    ]
}

{
    "title": "7. Reguły gramatyczne",
    "sections": [
        {
            "label": "W liczbie pojedynczej czy mnogiej?",
            "color": "emerald",
            "description": "Wszystkie zaimki nieokreślone są gramatycznie <strong>w liczbie pojedynczej</strong>, nawet każdy/wszyscy.",
            "examples": [
                {
                    "en": "Ktoś dzwoni. (✓)",
                    "ua": "Ktoś dzwoni."
                },
                {
                    "en": "Nikt nie wie. (✓)",
                    "ua": "Nikt nie wie."
                },
                {
                    "en": "Wszyscy przybyli. (✓)",
                    "ua": "Wszystkie dotarły."
                }
            ],
            "note": "📌 Jest, ma, robi (nie jest, ma, robi). coś (✗)"
        },
        {
            "label": "З прикметниками",
            "color": "blue",
            "description": "Прикметники ставляться <strong>після</strong> неозначеного займенника.",
            "examples": [
                {
                    "en": "something interesting (✓)",
                    "ua": "щось цікаве"
                },
                {
                    "en": "interesting something (✗)",
                    "ua": "BŁĄD"
                },
                {
                    "en": "ktoś wyjątkowy",
                    "ua": "ktoś wyjątkowy"
                },
                {
                    "en": "nic ważnego",
                    "ua": "nic ważnego"
                }
            ],
            "note": "📌 Zaimek nieokreślony + przymiotnik (po, nie wcześniej)."
        },
        {
            "label": "Zaimki zwrotne",
            "color": "purple",
            "description": "Aby zwrócić się do każdego/kogoś, używamy oni/ich (choć gramatycznie w liczbie pojedynczej).",
            "examples": [
                {
                    "en": "Ktoś zostawił torbę. (✓)",
                    "ua": "Ktoś zostawił torbę."
                },
                {
                    "en": "Każdy powinien odrobić pracę domową.",
                    "ua": "Każdy powinien odrobić swoją pracę domową."
                }
            ],
            "note": "📌 Używamy ich/ich w celu zachowania neutralności (nie on/jego)."
        }
    ]
}

{
    "title": "8. Typowe błędy osób mówiących po ukraińsku",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Podwójna negacja (nie + nie-).",
            "wrong": "Nie widziałem nikogo. / Nic nie powiedziała.",
            "right": "​​​​ <span class="font-mono">Nikogo nie widziałem. / Nic nie powiedziała.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Czasownik w liczbie mnogiej ze wszystkimi.",
            "wrong": "Wszyscy tu są. / Każdy ma bilety.",
            "right": " ✅ <span class="font-mono">Wszyscy tu są. / Każdy ma bilety.</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Przymiotnik przed zaimkiem.",
            "wrong": "Chcę czegoś ciekawego. / Poznał kogoś wyjątkowego.",
            "right": " ✅ <span class="font-mono">Chcę czegoś interesującego. / Poznał kogoś wyjątkowego.</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Jakiekolwiek pytania (jeśli nie jest to propozycja).",
            "wrong": "Czy ktoś dzwonił? (pytanie ogólne)",
            "right": " ✅ <span class="font-mono">Czy ktoś dzwonił?</span> (general) / <span class="font-mono">Czy ktoś Ci pomógł?</span> (oczekujemy „tak”)"
        }
    ]
}

{
    "title": "10. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwy zaimek",
    "select_intro": "Wpisz w puste miejsca właściwy zaimek nieokreślony.",
    "selects": [
        {
            "label": "___ jest u drzwi (Ktoś / Każdy)",
            "prompt": "Co zaimek?"
        },
        {
            "label": "Czy ___ dzwonił? (ktoś / ktokolwiek)",
            "prompt": "Jaki zaimek?"
        },
        {
            "label": "___ zna odpowiedź (Nikt / Każdy)",
            "prompt": "Jaki zaimek?"
        },
        {
            "label": "___ gotowy (Wszyscy / Każdy)",
            "prompt": "Jaki zaimek?"
        },
        {
            "label": "Nie widziałem ___. (ktokolwiek / ktoś)",
            "prompt": "Jaki zaimek?"
        }
    ],
    "options": [
        "ktoś",
        "każdy",
        "nikt",
        "wszyscy[[[CODX_SE G_7]]]coś",
        "something",
        "coś",
        "nic",
        "wszystko"
    ],
    "input_title": "Ćwiczenie 2. Uzupełnij luki",
    "input_intro": "Wpisz poprawny czas nieokreślony zaimek.",
    "inputs": [
        {
            "before": "___ zadzwonił do mnie. (ktoś dzwonił)",
            "after": "→"
        },
        {
            "before": "Widziałeś ___? (widziałem coś)",
            "after": "→"
        },
        {
            "before": "___ przyszedł na imprezę. (nikt nie przyszedł)",
            "after": "→"
        },
        {
            "before": "___ jest możliwe! (wszystko jest możliwe)",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Korekta błędów",
    "rephrase_intro": "Znajdź i popraw błąd z zaimkami nieokreślonymi.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Nie widziałem nikt.",
            "example_target": "Nie widziałem nikogo."
        },
        {
            "original": "1. Wszyscy są gotowi.",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Chcę czegoś ciekawego.",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "3. Nic nie powiedziała.",
            "placeholder": "Popraw błąd"
        }
    ]
}

{
    "title": "Inne strony z kategorii Zaimki i słowa orientacyjne",
    "items": [
        {
            "label": "Zaimki - Zaimki (przegląd)",
            "current": false
        },
        {
            "label": "Zaimki osobowe i przedmiotowe - osobowe i dopełnienia obiekt",
            "current": false
        },
        {
            "label": "Przymiotniki dzierżawcze a zaimki — mój / moje",
            "current": false
        },
        {
            "label": "Zaimki nieokreślone — ktoś, ktokolwiek, nikt, nic",
            "current": true
        }
    ]
}
